mapper.select:
select pm.id, pm.project_id, pm.payment_type, pm.amount, pm.pay_time, pm.pay_unit, pm.pay_method, pm.extra_data::text as extra_data, pm.del_flag, pm.create_by, pm.create_time, pm.update_by, pm.update_time, pm.remark, p.project_name from proj_payment pm left join proj_project p on p.id = pm.project_id where pm.del_flag = '0'
and pm.project_id = #{projectId}
and pm.payment_type = #{paymentType}
and pm.pay_unit like concat('%', #{payUnit}, '%')
order by pm.id desc

mapper.update:
update proj_payment
project_id = #{projectId}, payment_type = #{paymentType}, amount = #{amount}, pay_time = #{payTime}, pay_unit = #{payUnit}, pay_method = #{payMethod}, extra_data = #{extraData}::jsonb, remark = #{remark}, update_by = #{updateBy}, update_time = now()
where id = #{id}
